    _report(_DEST_PYCMN, synced_pycmm, changed_pycmm, wrote_pycmm)
    _report(_DEST_PYMISC, synced_pymisc, changed_pymisc, wrote_pymisc)
    _report(_DEST_MBDIFF, synced_mbdiff, changed_mbdiff, wrote_mbdiff)
    _report(_DEST_UXLC39, synced_uxlc39, changed_uxlc39, wrote_uxlc39)
