def _parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--force-provenance",
        action="store_true",
        help=(
            "Rewrite each _provenance.md even when no vendored file content changed. "
            "By default _provenance.md is left untouched (no date/commit bump) when "
            "the sync copied no new content."
        ),
    )
    return parser.parse_args()


def _sync(
    src_dir: Path, dest_dir: Path, suffixes: tuple[str, ...]
) -> tuple[list[str], bool]:
    """Copy src_dir into dest_dir, returning (copied_files, content_changed)."""
    before = _content_digest(dest_dir, suffixes)
    copied = vendoring_sync.copy_by_intersection(
        src_dir,
        dest_dir,
        include_suffixes=suffixes,
        strict=True,
    )
    changed = _content_digest(dest_dir, suffixes) != before
    return copied, changed


def _content_digest(dest_dir: Path, suffixes: tuple[str, ...]) -> dict[str, str]:
    """Map each matching dest filename to a hash of its bytes (non-recursive)."""
    digest: dict[str, str] = {}
    for path in dest_dir.iterdir():
        if not path.is_file() or "__pycache__" in path.parts:
            continue
        if path.suffix not in suffixes:
            continue
        digest[path.name] = hashlib.sha256(path.read_bytes()).hexdigest()
    return digest


def _maybe_write_provenance(
    dest_dir: Path,
    *,
    source_rel: str,
    copied_files,
    commit: str,
    tag: str | None,
    date_str: str,
    changed: bool,
    force: bool,
) -> bool:
    """Write _provenance.md only when content changed (or force). Return whether written."""
    if not (changed or force):
        return False
    vendoring_sync.write_provenance(
        dest_dir,
        source_rel=source_rel,
        copied_files=copied_files,
        commit=commit,
        tag=tag,
        date_str=date_str,
    )
    return True


def _report(dest_dir: Path, copied: list[str], changed: bool, wrote: bool) -> None:
    if wrote:
        provenance = "provenance updated" if changed else "provenance forced"
    else:
        provenance = "unchanged, provenance kept"
    print(f"{dest_dir.relative_to(_REPO)}: copied {len(copied)} files ({provenance})")


def _require_dir(path: Path) -> None:
    if not path.is_dir():
        raise FileNotFoundError(f"Directory does not exist: {path}")


if __name__ == "__main__":
    force_utf8_io()
    main()
